#include <iostream>
void printSign(int x) {
    if (x > 0) { std::cout << "+"; return; }
    if (x < 0) { std::cout << "-"; return; }
    std::cout << "0";
}
int main() {
    printSign(5);
    printSign(-3);
    printSign(0);
}

#include <iostream>
void swap(int a, int b) {
    int tmp = a;
    a = b;
    b = tmp;
}
int main() {
    int x = 1, y = 2;
    swap(x, y);
    std::cout << x << " " << y;
}

#include <iostream>
void printN(char c, int n) {
    for (int i{0}; i < n; ++i)
        std::cout << c;
}
int main() {
    printN('*', 4);
}

#include <iostream>
void check(int x) {
    if (x < 0) {
        std::cout << "neg";
        return;
    }
    std::cout << "pos";
}
int main() {
    check(-1);
    check(5);
}
